const {BigQuery} = require('@google-cloud/bigquery');
const bigquery = new BigQuery();

exports.processData = async (req, res) => {
  const projectId = 'YOUR PROJECT ID';

  // Create a reference to the dataset and table.
  const datasetId = 'YOUR DATASET ID';
  const tableId = 'YOUR TABLE ID';
  const dataset = bigquery.dataset(datasetId);
  const table = dataset.table(tableId);

  let query = `SELECT COUNT(*) FROM ${table}`;

  // Run the query as a job.
  try {
    await bigquery
      .createQueryJob({
        query,
        destinationTable: {
          projectId,
          datasetId,
          tableId,
        },
        writeDisposition: 'WRITE_TRUNCATE',
        priority: 'BATCH'
      })
      .then(job => {
        console.log(`Job ${job.id} started.`);

        job.on('complete', () => {
          res.status(200).send({message:'Job completed.'});
        });

        job.on('error', err => {
          res.status(500).send({message:err});
        });
      })
  } catch (e) {
    console.log(`Error processing query ${query}: ${e}`);
    res.status(400).send({message:'Error processing query.'})
  }
};